int ImportResolver__load_module_companions(ImportResolver* r, string primary_file, string cneo_root, string dir_path) {
  string dir_full = string_plus_many(3, (string[3]){cneo_root, dir_path, _str_153});
  array files = os__ls_dir(dir_full);
  files.element_size = sizeof(string);
  if ((files.len == 0)) 
{
    return 0;
  }
  array filtered = Preferences__should_compile_filtered_files(r->prefs, dir_full, files);
  filtered.element_size = sizeof(string);
  int loaded = 0;
  int fi = 0;
  while (fi < filtered.len) {
    string fname = ((string*)filtered.data)[fi];
    fi++;
    string full_path = string_plus_many(2, (string[2]){dir_full, fname});
    if (cneo_str_eq(full_path, primary_file)) 
{
      continue;
    }
    if (map_ss_has(&r->imported, full_path)) 
{
      continue;
    }
    string src = main__read_file_contents(full_path);
    if (cneo_str_eq(src, _str_144)) 
{
      continue;
    }
    if (r->verbose) 
{
      eprintln_str(string_plus_many(5, (string[5]){_str_2914, full_path, _str_2915, cneo_int_to_str(src.len), _str_2916}));
    }
    map_ss_set_bool(&r->imported, full_path, 1);
    Parser cp = parser__new(r->a);
    Parser__init(&cp, full_path, src);
    if ((r->errs != 0)) 
{
      Parser__set_errs(&cp, r->errs);
      Errors__register_source(r->errs, full_path, src);
    }
    Parser__next(&cp);
    int cfid = Parser__parse_file(&cp);
    array_push(&r->file_ids, &cfid);
    loaded++;
    ImportResolver__resolve(r, cfid, full_path);
  }
  return loaded;
}

